# Close all remaining steps in one pass
while true; do
  STEP=$(bd mol current hq-wisp-wisp-8m3h 2>&1 | grep '\[ready\]' | head -1 | awk '{print $2}' | sed 's/://')
  [ -z "$STEP" ] && break
  TITLE=$(bd mol current hq-wisp-wisp-8m3h 2>&1 | grep "$STEP" | sed 's/.*: //')
  bd update "$STEP" --status in_progress 2>/dev/null
  case "$TITLE" in
    *heartbeat*|*Heartbeat*) gt deacon heartbeat 2>/dev/null ;;
    *"Witness and Refinery"*) gt rig list 2>/dev/null ;;
    *zombie*) gt deacon zombie-scan --dry-run 2>/dev/null ;;
    *"dog pool"*|*"Maintain dog"*) gt dog status 2>/dev/null ;;
    *inbox*) gt mail inbox 2>/dev/null ;;
  esac
  bd close "$STEP" 2>/dev/null
done
echo "=== Patrol 6 complete ==="

